class Solution {
public:
    int countPairs(vector<int>& nums, int low, int high) {
        int n = nums.size();
        int ans = 0;
        unordered_map<int, int> cnt;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (low <= (nums[i] ^ nums[j]) && (nums[i] ^ nums[j]) <= high) {
                    ans++;
                }
            }
        }
        return ans;
    }
};
